class Solution {
    public String resultingString(String s) {
        while (s.length() >= 2 && isConsecutive(s.charAt(0), s.charAt(1))) {
            s = s.substring(2) + s.substring(1, 2);
        }
        return s;
    }
    private boolean isConsecutive(char a, char b) {
        return Math.abs((int)a - (int)b) == 1 || (a == 'z' && b == 'a') || (b == 'z' && a == 'a');
    }
}
```
